import Pagination from 'react-bootstrap/Pagination';

const PaginationComponent = ({
  currentPage,
  totalPages,
  onPageChange
}) => {
  const pageNumbers = [];

  const maxVisible = 2;

  const startPage = Math.max(2, currentPage - maxVisible);
  const endPage = Math.min(totalPages - 1, currentPage + maxVisible);

  // First page
  pageNumbers.push(1);

  // Left ellipsis
  if (startPage > 2) {
    pageNumbers.push('left-ellipsis');
  }

  // Middle pages
  for (let i = startPage; i <= endPage; i++) {
    pageNumbers.push(i);
  }

  // Right ellipsis
  if (endPage < totalPages - 1) {
    pageNumbers.push('right-ellipsis');
  }

  // Last page
  if (totalPages > 1) {
    pageNumbers.push(totalPages);
  }

  return (
    <Pagination>
      <Pagination.Prev
        disabled={currentPage === 1}
        onClick={() => onPageChange(currentPage - 1)}
      />

      {pageNumbers.map((page, index) => {
        if (page === 'left-ellipsis' || page === 'right-ellipsis') {
          return <Pagination.Ellipsis key={index} disabled />;
        }

        return (
          <Pagination.Item
            key={index}
            active={page === currentPage}
            onClick={() => onPageChange(page)}
          >
            {page}
          </Pagination.Item>
        );
      })}

      <Pagination.Next
        disabled={currentPage === totalPages}
        onClick={() => onPageChange(currentPage + 1)}
      />
    </Pagination>
  );
};

export default PaginationComponent;
