import React, { useEffect, useState } from 'react'
import { Notification } from '../../../Constant'
import { Breadcrumbs, H3, P } from '../../../AbstractElements'
import { Card, CardBody, CardHeader } from 'reactstrap'
import { useDispatch, useSelector } from 'react-redux'
import { getNotification, getNotificationCount, getNotificationCountRole, getNotificationDelete, getNotificationDeleteRole, getNotificationRole, getNotificationUpdate, getNotificationUpdateRole } from '../../../CommonUrl'
import { getClientUrlDataToken, postClientUrlWithToken } from '../../../Utils/restUtils'
import { FCPThresholds } from 'web-vitals'
import { CiClock1 } from "react-icons/ci";
import { useNavigate } from 'react-router'
import { CgCross } from 'react-icons/cg'
import { RxCrossCircled } from "react-icons/rx";
import Transparentspinner from '../../../Components/Common/Loader/Transparentspinner'
import { setNotificationCount } from '../../../Redux/NotificationReducer'
import { Button, OverlayTrigger, Tooltip } from 'react-bootstrap'
import PaginationComponent from '../../../Components/Common/pagination/PaginationComponent'



function NotificationList() {
    const [notifiacitonData, setNotificationData] = useState([])
    const [spinnerTrans, setspinnerTrans] = useState(false)
    const [page, setPage] = useState(1);
    const [totalPage, setTotalPage] = useState(1);

    const authState = useSelector((state) => state.auth);
    const navigate = useNavigate()
    const dispatch = useDispatch()



    const handleApiError = (status) => {
        if (status >= 400 && status <= 405) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (status >= 500 && status <= 505) {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
            navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
    };

    const notificationCount = async () => {
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getNotificationCount :
            getNotificationCountRole)
        dispatch(setNotificationCount(response?.data))

    };

    const fetchNotification = async (currentPage=page) => {
        setspinnerTrans(true)
        const response = await getClientUrlDataToken(authState.apiUrl, authState.userRole === 1 ? getNotification+`?page=${currentPage}&page_length=10` : getNotificationRole+`?page=${currentPage}&page_length=10`)

        if (response?.status === true) {
            setNotificationData(response?.data?.data)
            setTotalPage(response?.data?.last_page)
        }
        else {
            handleApiError(response?.status)
        }
        setspinnerTrans(false)
    };

    const updateNotification = async (id, reqID) => {
        setspinnerTrans(true)

        const postRequest = {
            notification_id: id
        }

        const updateResponce = await postClientUrlWithToken(

            authState.apiUrl,
            authState.userRole === 1 ? getNotificationUpdate : getNotificationUpdateRole,
            postRequest
        );
        if (updateResponce?.status === 200) {
            notificationCount()
            fetchNotification()
            setspinnerTrans(false)

            navigate(`/complaints/complaint-show?id=${reqID}`)
        }
        setspinnerTrans(false)


    }
    const deleteNotification = async (id) => {
        setspinnerTrans(true)

        const postRequest = {
            notification_id: id
        }

        const updateResponce = await postClientUrlWithToken(

            authState.apiUrl,
            authState.userRole === 1 ? getNotificationDelete : getNotificationDeleteRole,
            postRequest
        );
        if (updateResponce?.status === 200) {
            notificationCount()
            fetchNotification(1)
        }
        setspinnerTrans(false)


    }
    // change notification list page 
    const handleChangePage = (page) => {
        setPage(page)
        fetchNotification(page)
    }




    useEffect(() => {
        fetchNotification()
    }, [])
    return (
        <>
            {spinnerTrans && <Transparentspinner />}
            <Breadcrumbs mainTitle={Notification} parent="Notification" title={Notification} />
            <Card className='cardWidth'>
                <CardHeader style={{ margin: '-2px 0 -40px', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
                    {/* <H3>{Notification}</H3> */}

                </CardHeader>
                <CardBody className=''>


                    {
                        notifiacitonData?.length === 0 ? <p className='text-center'>No notifications available</p> :
                            notifiacitonData?.map((item) => (
                                <div key={item?.id} className='mt-3 p-2' style={{ borderBottom: 'solid 1px #dedcdc' }} >
                                    {/* <span className='badge badge-'>fd</span> */}
                                    <div className='d-flex justify-content-between'>
                                        <span style={{ color: '#6c6c6c' }} className={`cursor-pointer ${item?.read_status === 1 ? "fw-normal h4" : "h4"} `}>{item?.title}</span>
                                        <div className='d-flex gap-2 align-items-center'>

                                            <div className='d-flex gap-2' style={{ color: '#6c6c6c' }}>
                                                <CiClock1 />

                                                <p className='' style={{ fontSize: '11px' }}>{item?.created_date}</p>|

                                            </div>
                                            <OverlayTrigger
                                                placement="top"
                                                overlay={
                                                    <Tooltip
                                                        id="tooltip-top"

                                                    >
                                                        <span style={{ fontSize: '11px', color: 'black', letterSpacing: '1px' }} >Delete</span>
                                                    </Tooltip>
                                                }
                                            >
                                                <span
                                                    className="text-danger d-flex"
                                                    style={{ cursor: "pointer" }}
                                                    onClick={() => deleteNotification(item?.id)}
                                                >
                                                    <RxCrossCircled size={18} />
                                                </span>
                                            </OverlayTrigger>


                                        </div>
                                    </div>
                                    <div className='d-flex align-items-center gap-2'>


                                        <span
                                            className={`cursor-pointer ${item?.read_status === 1 ? "fw-normal" : "fw-bod"} `}
                                            onClick={() => updateNotification(item?.id, item?.complaint_id)} style={{ color: `${item?.read_status === 1 ? "#6c6c6c" : ""}`, cursor: 'pointer' }}

                                        >
                                            {item?.message}
                                        </span>
                                    </div>
                                </div>

                            ))
                    }
                    <div className='d-flex justify-content-end mt-4'>

                        <PaginationComponent
                            currentPage={page}
                            totalPages={totalPage}
                            onPageChange={handleChangePage}
                        />
                    </div>

                </CardBody>
            </Card>

        </>)
}

export default NotificationList